mapper.select:
SELECT

FROM guild_operation_log gol
LEFT JOIN guild g ON gol.guild_id = g.id
LEFT JOIN sys_user u ON gol.operator_id = u.user_id

    AND gol.guild_id = #{guildId}
    AND gol.operator_id = #{operatorId}
    AND u.nick_name LIKE CONCAT('%', #{operatorName}, '%')
    AND gol.operation_type = #{operationType}

ORDER BY gol.created_at DESC

mapper.insert:
